import React from 'react';
import { CartItem } from '../types';
import { CONTACT_PHONE } from '../constants';

interface CartProps {
  items: CartItem[];
  onRemove: (id: string) => void;
  onUpdateQuantity: (id: string, delta: number) => void;
  isOpen: boolean;
  onClose: () => void;
}

const Cart: React.FC<CartProps> = ({ items, onRemove, onUpdateQuantity, isOpen, onClose }) => {
  const total = items.reduce((sum, item) => sum + item.price * item.quantity, 0);

  const handleSendWhatsApp = () => {
    if (items.length === 0) return;

    let message = `Olá Rhay's Candy Store! Gostaria de fazer um pedido:\n\n`;
    items.forEach((item) => {
      message += `*${item.quantity}x ${item.name}* - R$ ${(item.price * item.quantity).toFixed(2)}\n`;
    });
    message += `\n*Total: R$ ${total.toFixed(2)}*`;

    const encodedMessage = encodeURIComponent(message);
    window.open(`https://wa.me/${CONTACT_PHONE}?text=${encodedMessage}`, '_blank');
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex justify-end">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={onClose}
      />

      {/* Cart Drawer */}
      <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
        <div className="p-6 border-b flex items-center justify-between">
          <h2 className="text-xl font-bold text-[#5C3D2E] flex items-center gap-2">
            <i className="fas fa-shopping-basket text-[#E89E7D]"></i>
            Meu Pedido
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
            <i className="fas fa-times text-gray-400"></i>
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6">
          {items.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center text-gray-400">
              <i className="fas fa-cart-arrow-down text-5xl mb-4"></i>
              <p>Seu pedido está vazio.</p>
              <button 
                onClick={onClose}
                className="mt-4 text-[#E89E7D] font-medium underline"
              >
                Ver cardápio
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              {items.map((item) => (
                <div key={item.id} className="flex gap-4 p-4 rounded-2xl bg-orange-50/50 border border-orange-100">
                  <div className="flex-grow">
                    <h4 className="font-semibold text-[#5C3D2E]">{item.name}</h4>
                    <p className="text-[#E89E7D] font-bold">R$ {item.price.toFixed(2)}</p>
                    <div className="flex items-center gap-4 mt-2">
                      <div className="flex items-center gap-2 bg-white rounded-lg border border-orange-200 px-2">
                        <button 
                          onClick={() => onUpdateQuantity(item.id, -1)}
                          className="w-8 h-8 flex items-center justify-center text-[#E89E7D]"
                        >
                          <i className="fas fa-minus text-xs"></i>
                        </button>
                        <span className="w-4 text-center font-medium">{item.quantity}</span>
                        <button 
                          onClick={() => onUpdateQuantity(item.id, 1)}
                          className="w-8 h-8 flex items-center justify-center text-[#E89E7D]"
                        >
                          <i className="fas fa-plus text-xs"></i>
                        </button>
                      </div>
                      <button 
                        onClick={() => onRemove(item.id)}
                        className="text-red-400 text-sm hover:text-red-600"
                      >
                        Remover
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="p-6 border-t bg-gray-50">
          <div className="flex justify-between items-center mb-6">
            <span className="text-gray-500 font-medium">Total</span>
            <span className="text-2xl font-bold text-[#5C3D2E]">
              R$ {total.toFixed(2).replace('.', ',')}
            </span>
          </div>

          <button
            disabled={items.length === 0}
            onClick={handleSendWhatsApp}
            className="w-full bg-[#25D366] text-white py-4 rounded-2xl font-bold text-lg hover:bg-[#128C7E] transition-colors flex items-center justify-center gap-3 disabled:bg-gray-300 disabled:cursor-not-allowed"
          >
            <i className="fab fa-whatsapp text-2xl"></i>
            Enviar para WhatsApp
          </button>
          <p className="text-center text-xs text-gray-400 mt-4">
            Ao clicar, seu pedido será enviado diretamente para nós no WhatsApp.
          </p>
        </div>
      </div>
    </div>
  );
};

export default Cart;

import React, { useState, useCallback } from 'react';
import { MENU_ITEMS } from './constants';
import { MenuItem, CartItem } from './types';
import ItemCard from './components/ItemCard';
import Cart from './components/Cart';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);

  const addToCart = useCallback((item: MenuItem) => {
    setCart((prev) => {
      const existing = prev.find((i) => i.id === item.id);
      if (existing) {
        return prev.map((i) =>
          i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i
        );
      }
      return [...prev, { ...item, quantity: 1 }];
    });
    // Visual feedback
    setIsCartOpen(true);
  }, []);

  const updateQuantity = (id: string, delta: number) => {
    setCart((prev) =>
      prev.map((item) => {
        if (item.id === id) {
          const newQuantity = Math.max(1, item.quantity + delta);
          return { ...item, quantity: newQuantity };
        }
        return item;
      })
    );
  };

  const removeFromCart = (id: string) => {
    setCart((prev) => prev.filter((item) => item.id !== id));
  };

  const categories = ['Pastéis', 'Batatas'] as const;
  const cartCount = cart.reduce((sum, i) => sum + i.quantity, 0);

  return (
    <div className="min-h-screen pb-20">
      {/* Header / Logo Section */}
      <header className="bg-white px-4 py-8 text-center shadow-sm relative overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-64 h-64 bg-orange-100/50 rounded-full blur-3xl -z-10 opacity-30"></div>

        {/* Simulating the logo from the prompt image */}
        <div className="flex flex-col items-center mb-4 scale-90 sm:scale-100">
           {/* Custom SVG Logo mimic */}
          <div className="w-24 h-24 mb-2">
            <svg viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M50 5C35 25 35 75 50 95C65 75 65 25 50 5Z" fill="#E89E7D" stroke="#5C3D2E" strokeWidth="2"/>
              <path d="M50 5C45 25 45 75 50 95" stroke="#5C3D2E" strokeWidth="2"/>
              <path d="M50 5C55 25 55 75 50 95" stroke="#5C3D2E" strokeWidth="2"/>
              <path d="M50 95V100" stroke="#5C3D2E" strokeWidth="2"/>
            </svg>
          </div>
          <h1 className="brand-font text-5xl text-[#5C3D2E]">Rhay's</h1>
          <p className="uppercase tracking-widest font-bold text-[#5C3D2E] text-xl -mt-1">candy store</p>
        </div>

        <div className="w-24 h-1 bg-[#E89E7D] mx-auto rounded-full mt-4"></div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-8">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-3xl font-bold text-[#5C3D2E] relative">
            Nosso Cardápio
            <span className="absolute -bottom-2 left-0 w-12 h-1 bg-[#E89E7D] rounded-full"></span>
          </h2>

          <div className="text-[#5C3D2E]/60 text-sm hidden sm:block">
            <i className="fas fa-phone mr-1"></i> (85) 9 9626-9684
          </div>
        </div>

        {categories.map((category) => (
          <section key={category} className="mb-12">
            <div className="flex items-center gap-4 mb-6">
              <h3 className="text-2xl font-bold text-[#E89E7D] uppercase tracking-wider">
                {category}
              </h3>
              <div className="flex-grow h-px bg-orange-200"></div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {MENU_ITEMS.filter((item) => item.category === category).map((item) => (
                <ItemCard key={item.id} item={item} onAdd={addToCart} />
              ))}
            </div>
          </section>
        ))}

        {/* Footer Info */}
        <section className="mt-16 mb-24 p-8 bg-white rounded-3xl border border-orange-100 text-center">
          <h4 className="text-xl font-bold text-[#5C3D2E] mb-2">Informações Adicionais</h4>
          <p className="text-gray-500 max-w-md mx-auto">
            Nossas batatas acompanham molhos especiais, calabresa fritinha e queijo parmesão ralado na hora!
          </p>
          <div className="mt-6 flex justify-center gap-6">
             <div className="text-[#E89E7D] text-2xl">
               <i className="fab fa-instagram"></i>
             </div>
             <div className="text-[#E89E7D] text-2xl">
               <i className="fab fa-whatsapp"></i>
             </div>
          </div>
        </section>
      </main>

      {/* Persistent Call-to-Action / Floating Cart Button */}
      <div className="fixed bottom-6 left-0 right-0 flex justify-center px-6 pointer-events-none z-40">
        <button
          onClick={() => setIsCartOpen(true)}
          className="pointer-events-auto bg-[#5C3D2E] text-white px-8 py-4 rounded-full shadow-2xl flex items-center gap-4 hover:bg-[#4a3125] transition-all transform active:scale-95 group max-w-md w-full sm:w-auto"
        >
          <div className="relative">
            <i className="fas fa-shopping-basket text-xl"></i>
            {cartCount > 0 && (
              <span className="absolute -top-3 -right-3 bg-[#E89E7D] text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-[#5C3D2E]">
                {cartCount}
              </span>
            )}
          </div>
          <span className="font-bold tracking-wide uppercase text-sm flex-grow text-center">
            {cartCount > 0 ? `Ver Pedido (R$ ${cart.reduce((s, i) => s + i.price * i.quantity, 0).toFixed(2)})` : 'Seu Pedido está vazio'}
          </span>
          <i className="fas fa-chevron-right text-xs opacity-50 group-hover:translate-x-1 transition-transform"></i>
        </button>
      </div>

      <Cart
        items={cart}
        onRemove={removeFromCart}
        onUpdateQuantity={updateQuantity}
        isOpen={isCartOpen}
        onClose={() => setIsCartOpen(false)}
      />
    </div>
  );
};

export default App;

