              </button>
            </div>
          ) : (
            <div className="space-y-4">
              {items.map((item) => (
                <div key={item.id} className="flex gap-4 p-4 rounded-2xl bg-[#FDF1EB]/50 border border-orange-100 items-center">
                  <div className="flex-grow">
