          </h2>
          <button 
            onClick={onClose} 
            className="p-2 hover:bg-gray-100 rounded-full transition-colors"
            aria-label="Fechar carrinho"
          >
            <i className="fas fa-times text-gray-400"></i>
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6">
          {items.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center text-gray-400">
              <i className="fas fa-cart-arrow-down text-5xl mb-4"></i>
              <p>Seu carrinho está vazio.</p>
              <button 
                onClick={onClose}
                className="mt-4 text-[#E89E7D] font-medium underline hover:text-[#d48c6c]"
              >
                Voltar ao cardápio
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              {items.map((item) => (
                <div key={item.id} className="flex gap-4 p-4 rounded-2xl bg-[#FDF1EB]/50 border border-orange-100 items-center">
                  <div className="flex-grow">
                    <h4 className="font-semibold text-[#5C3D2E]">{item.name}</h4>
                    <p className="text-[#E89E7D] font-bold">R$ {item.price.toFixed(2).replace('.', ',')}</p>
                    <div className="flex items-center gap-4 mt-2">
                      <div className="flex items-center gap-2 bg-white rounded-lg border border-orange-200 px-1 shadow-sm">
                        <button 
                          onClick={() => onUpdateQuantity(item.id, -1)}
                          className="w-8 h-8 flex items-center justify-center text-[#E89E7D] hover:bg-orange-50 rounded"
                          aria-label="Diminuir quantidade"
                        >
                          <i className="fas fa-minus text-[10px]"></i>
                        </button>
                        <span className="w-6 text-center font-bold text-sm">{item.quantity}</span>
                        <button 
                          onClick={() => onUpdateQuantity(item.id, 1)}
                          className="w-8 h-8 flex items-center justify-center text-[#E89E7D] hover:bg-orange-50 rounded"
                          aria-label="Aumentar quantidade"
                        >
                          <i className="fas fa-plus text-[10px]"></i>
                        </button>
                      </div>
                      <button 
                        onClick={() => onRemove(item.id)}
                        className="text-red-400 text-xs hover:text-red-600 transition-colors uppercase font-bold tracking-tighter"
                      >
                        Remover
                      </button>
                    </div>
                  </div>
                </div>
              ))}

              {/* Seção PIX */}
              <div className="mt-8 p-6 rounded-3xl bg-[#FDF1EB] border-2 border-dashed border-[#E89E7D]/30 flex flex-col items-center text-center">
                <h3 className="text-[#5C3D2E] font-bold text-sm uppercase tracking-widest mb-4">Pagamento via PIX</h3>
                <div className="bg-white p-3 rounded-2xl shadow-sm mb-4">
                  <img 
                    src={qrCodeUrl} 
                    alt="QR Code PIX" 
                    className="w-32 h-32 sm:w-40 sm:h-40"
                  />
                </div>
                <p className="text-[#5C3D2E] font-medium text-sm mb-2">Chave: {PIX_KEY}</p>
                <button 
                  onClick={handleCopyPix}
                  className={`text-xs px-4 py-2 rounded-full font-bold transition-all ${copied ? 'bg-green-500 text-white' : 'bg-[#E89E7D]/20 text-[#E89E7D] hover:bg-[#E89E7D]/30'}`}
                >
