              <button 
                onClick={onClose}
                className="mt-4 text-[#E89E7D] font-medium underline hover:text-[#d48c6c]"
              >
                Voltar ao cardápio
              </button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="space-y-4">
                {items.map((item) => (
